sys_ui_page.client_script:
// ============================================
// SVEM EMPLOYEE PORTAL v3 - Jobs-Based System
// ============================================

var API_BASE = '/api/now/table';
var HEADERS = {
    'Accept': 'application/json',
    'Content-Type': 'application/json',
    'X-UserToken': window.g_ck || ''
};

// State
var isManager = window._svemIsAdmin === 'true';
var currentUserName = window._svemUserName || 'admin';
var currentUserFullName = window._svemFullName || '';
var staffRecord = null;
var allStaff = [];
var myJobs = [];
var allJobs = [];
var allMachines = [];
var activeTimer = null;
var timerStart = null;
var timerElapsed = 0;
var selectedMachineSysId = null;
var selectedMachineStatus = null;
var clockedIn = false;

var viewAsStaffId = null; // Manager "View As" override

// ---- INIT ----
window.onload = function() {
    setupRoleUI();
    portalInit();
};

function setupRoleUI() {
    // Show/hide tabs based on role
    var mgrTabs = document.querySelectorAll('.mgr-only');
    var empTabs = document.querySelectorAll('.emp-only');
    for (var i = 0; i < mgrTabs.length; i++) {
        mgrTabs[i].style.display = isManager ? '' : 'none';
    }
    // Update tab grid columns
    var bottomTabs = document.getElementById('bottomTabs');
    if (isManager) {
        bottomTabs.style.gridTemplateColumns = 'repeat(6, 1fr)';
    } else {
        bottomTabs.style.gridTemplateColumns = 'repeat(3, 1fr)';
    }
    // Update role badge in header
    var roleBadge = document.getElementById('roleBadge');
    if (roleBadge) {
        roleBadge.innerHTML = isManager ? 'MANAGER' : 'EMPLOYEE';
        roleBadge.className = 'role-badge ' + (isManager ? 'manager' : 'employee');
    }
}

function portalInit() {
    loadAllStaff().then(function() {
        return Promise.all([loadMachines(), loadJobs()]);
    }).then(function() {
        filterMyJobs();
        renderTasks();
        renderMachines();
        renderProfile();
        if (isManager) {
            renderTeam();
            renderAssignments();
            renderReview();
        }
    }).catch(function(e) {
        console.error('Init error:', e);
        showToast('Error loading data: ' + e.message, 'error');
    });
}

// ---- API HELPERS ----
function apiGet(table, params) {
    var url = API_BASE + '/' + table;
    if (params) {
        var qs = [];
        for (var k in params) { qs.push(encodeURIComponent(k) + '=' + encodeURIComponent(params[k])); }
        url += '?' + qs.join('&');
    }
    return fetch(url, { method: 'GET', headers: HEADERS })
        .then(function(res) {
            if (!res.ok) throw new Error('API error: ' + res.status);
            return res.json();
        })
        .then(function(data) { return data.result || []; });
}

function apiPatch(table, sysId, data) {
    return fetch(API_BASE + '/' + table + '/' + sysId, {
        method: 'PATCH', headers: HEADERS, body: JSON.stringify(data)
    }).then(function(res) {
        if (!res.ok) throw new Error('API error: ' + res.status);
        return res.json();
    }).then(function(data) { return data.result; });
}

function apiPost(table, data) {
    return fetch(API_BASE + '/' + table, {
        method: 'POST', headers: HEADERS, body: JSON.stringify(data)
    }).then(function(res) {
        if (!res.ok) throw new Error('API error: ' + res.status);
        return res.json();
    }).then(function(data) { return data.result; });
}

function ev(field) {
    if (!field) return '';
    if (typeof field === 'object') return field.display_value || field.value || '';
    return field;
}

function eid(field) {
    if (!field) return '';
    if (typeof field === 'object') return field.value || '';
    return field;
}

// ---- LOAD DATA ----
function loadAllStaff() {
    return apiGet('x_1964226_svem_com_staff', {
        sysparm_display_value: 'all',
        sysparm_fields: 'sys_id,name,employee_id,role,shift,status,current_job,current_machine,current_operation,jobs_completed_this_week,notes',
        sysparm_limit: '200'
    }).then(function(staff) {
        allStaff = staff;
        // Find current user's staff record
        staffRecord = null;
        for (var i = 0; i < staff.length; i++) {
            if (ev(staff[i].name) === currentUserFullName) { staffRecord = staff[i]; break; }
        }
        if (!staffRecord && staff.length > 0) staffRecord = staff[0];

        // Update header
        var name = staffRecord ? ev(staffRecord.name) : currentUserFullName;
        document.getElementById('userName').innerHTML = escHtml(name || 'Employee');
        document.getElementById('userAvatar').innerHTML = name ? name.charAt(0).toUpperCase() : '?';
        var role = staffRecord ? ev(staffRecord.role) : '';
        document.getElementById('userRole').innerHTML = role ? formatRole(role) : (isManager ? 'Manager' : 'Employee');

        // Clock status
        if (staffRecord) {
            var status = ev(staffRecord.status);
            clockedIn = (status === 'available' || status === 'assigned');
            updateClockBtn();
        }
    });
}

function loadMachines() {
    return apiGet('x_1964226_svem_com_machines', {
        sysparm_display_value: 'all',
        sysparm_fields: 'sys_id,machine_name,machine_number,machine_type,status,current_job,current_operation,uptime_percentage',
        sysparm_limit: '50'
    }).then(function(m) { allMachines = m; });
}

function loadJobs() {
    return apiGet('x_1964226_svem_com_jobs', {
        sysparm_display_value: 'all',
        sysparm_fields: 'sys_id,job_number,po_number,customer,job_status,priority,assigned_to,assigned_machine,customer_due_date,ship_by_date,quantity_due,notes,days_until_due',
        sysparm_query: 'ORDERBYpriority',
        sysparm_limit: '200'
    }).then(function(j) { allJobs = j; });
}

function filterMyJobs() {
    if (!staffRecord) { myJobs = allJobs; return; }
    var mySysId = eid(staffRecord.sys_id);
    var myName = ev(staffRecord.name);
    myJobs = [];
    for (var i = 0; i < allJobs.length; i++) {
        var assignedId = eid(allJobs[i].assigned_to);
        var assignedName = ev(allJobs[i].assigned_to);
        if (assignedId === mySysId || assignedName === myName) {
            myJobs.push(allJobs[i]);
        }
    }
    // If no specific assignments and employee, show all active jobs
    if (myJobs.length === 0 && !isManager) {
        for (var j = 0; j < allJobs.length; j++) {
            var st = ev(allJobs[j].job_status);
            if (st !== 'complete' && st !== 'shipped') {
                myJobs.push(allJobs[j]);
            }
        }
    }
}

// ---- RENDER: MY TASKS (Employee) ----
function renderTasks() {
    var container = document.getElementById('myOperations');
    var activeArea = document.getElementById('activeTaskArea');

    var activeJob = null;
    for (var i = 0; i < myJobs.length; i++) {
        if (ev(myJobs[i].job_status) === 'in_progress') { activeJob = myJobs[i]; break; }
    }

    if (activeJob) {
        var jobNum = ev(activeJob.job_number);
        var pri = ev(activeJob.priority);
        var jobSysId = eid(activeJob.sys_id);
        activeArea.innerHTML = '<div class="active-task">' +
            '<div class="active-task-label">&#9654; Currently Working On</div>' +
            '<div class="active-task-job">' + escHtml(jobNum) + '</div>' +
            '<div class="active-task-op">' + escHtml(ev(activeJob.po_number)) + ' &bull; Priority: ' + escHtml(pri).toUpperCase() + ' &bull; Qty: ' + ev(activeJob.quantity_due) + '</div>' +
            '<div class="active-task-timer" id="taskTimer">00:00:00</div>' +
            '<div class="active-task-actions">' +
                '<button class="action-btn warning" onclick="pauseJob(\'' + jobSysId + '\')">&#10074;&#10074; Pause</button>' +
                '<button class="action-btn primary" onclick="submitJobForReview(\'' + jobSysId + '\')">&#10148; Submit for Review</button>' +
            '</div>' +
        '</div>';
        startTimer();
    } else {
        activeArea.innerHTML = '';
        stopTimer();
    }

    // Group by status
    var staged = { assigned: [], pending_review: [], not_started: [] };
    for (var j = 0; j < myJobs.length; j++) {
        var st = ev(myJobs[j].job_status);
        if (st === 'in_progress' || st === 'complete' || st === 'shipped') continue;
        if (staged[st]) staged[st].push(myJobs[j]);
        else staged.not_started.push(myJobs[j]);
    }

    var html = '';

    if (staged.pending_review.length > 0) {
        html += '<div class="stage-label review">&#9201; Pending Manager Review (' + staged.pending_review.length + ')</div>';
        html += renderJobList(staged.pending_review, false);
    }

    if (staged.assigned.length > 0) {
        html += '<div class="stage-label assigned">&#128204; Assigned to You (' + staged.assigned.length + ')</div>';
        html += renderJobList(staged.assigned, true);
    }

    if (staged.not_started.length > 0) {
        html += '<div class="stage-label queued">&#128203; Not Started (' + staged.not_started.length + ')</div>';
        html += renderJobList(staged.not_started, false);
    }

    if (html === '' && !activeJob) {
        html = '<div class="empty-state"><p>No pending jobs.</p></div>';
    }

    container.innerHTML = html;
}

function renderJobList(jobs, canStart) {
    var html = '';
    for (var i = 0; i < jobs.length; i++) {
        var job = jobs[i];
        var status = ev(job.job_status) || 'not_started';
        var jobNum = ev(job.job_number);
        var poNum = ev(job.po_number);
        var pri = ev(job.priority);
        var qty = ev(job.quantity_due);
        var dueDate = ev(job.customer_due_date);
        var assignee = ev(job.assigned_to);
        var sid = eid(job.sys_id);

        var priClass = pri === 'critical' ? 'danger' : (pri === 'high' ? 'warning' : '');
        html += '<div class="op-item" onclick="' + (canStart ? 'startJobConfirm(\'' + sid + '\')' : '') + '">' +
            '<div class="op-seq' + (priClass ? ' ' + priClass : '') + '" style="' +
                (pri === 'critical' ? 'background:rgba(239,68,68,0.2);color:#EF4444;' :
                 pri === 'high' ? 'background:rgba(245,158,11,0.2);color:#F59E0B;' : '') + '">' +
                escHtml(pri ? pri.charAt(0).toUpperCase() : '?') + '</div>' +
            '<div class="op-info">' +
                '<div class="op-name">' + escHtml(jobNum) + '</div>' +
                '<div class="op-meta">' +
                    '<span>' + escHtml(poNum) + '</span>' +
                    '<span>Qty: ' + qty + '</span>' +
                    (dueDate ? '<span>Due: ' + escHtml(dueDate) + '</span>' : '') +
                    (assignee ? '<span>&#128100; ' + escHtml(assignee) + '</span>' : '') +
                '</div>' +
            '</div>' +
            '<span class="badge ' + status + '">' + status.replace(/_/g, ' ') + '</span>' +
        '</div>';
    }
    return html;
}

// ---- RENDER: TEAM (Manager Only) ----
function renderTeam() {
    var container = document.getElementById('teamList');
    if (!container) return;

    // Populate View As dropdown
    var viewAs = document.getElementById('viewAsSelect');
    if (viewAs && viewAs.options.length <= 1) {
        var vopts = '<option value="">View as yourself</option>';
        for (var v = 0; v < allStaff.length; v++) {
            vopts += '<option value="' + eid(allStaff[v].sys_id) + '">' + escHtml(ev(allStaff[v].name)) + ' (' + formatRole(ev(allStaff[v].role)) + ')</option>';
        }
        viewAs.innerHTML = vopts;
    }

    // Render org chart
    renderOrgChart();

    var activeCount = 0;
    for (var i = 0; i < allStaff.length; i++) {
        var s = ev(allStaff[i].status);
        if (s === 'available' || s === 'assigned') activeCount++;
    }
    document.getElementById('teamCount').innerHTML = activeCount + '/' + allStaff.length + ' active';

    if (allStaff.length === 0) {
        container.innerHTML = '<div class="empty-state"><p>No staff records found. Add your first team member!</p></div>';
        return;
    }

    var html = '';
    var groups = { available: [], assigned: [], off: [] };
    for (var j = 0; j < allStaff.length; j++) {
        var st = ev(allStaff[j].status) || 'off';
        if (!groups[st]) groups[st] = [];
        groups[st].push(allStaff[j]);
    }

    var order = ['assigned', 'available', 'off'];
    var labels = { assigned: '&#128994; Working', available: '&#128309; Available', off: '&#9899; Off Shift' };

    for (var g = 0; g < order.length; g++) {
        var grp = groups[order[g]];
        if (!grp || grp.length === 0) continue;
        html += '<div class="stage-label ' + order[g] + '">' + labels[order[g]] + ' (' + grp.length + ')</div>';
        for (var k = 0; k < grp.length; k++) {
            var m = grp[k];
            var name = ev(m.name);
            var role = ev(m.role);
            var empId = ev(m.employee_id);
            var curJob = ev(m.current_job);
            var curMachine = ev(m.current_machine);
            var status = ev(m.status);
            var sid = eid(m.sys_id);

            html += '<div class="team-card" onclick="openStaffDetail(\'' + sid + '\')">' +
                '<div class="team-avatar">' + (name ? name.charAt(0).toUpperCase() : '?') + '</div>' +
                '<div class="team-info">' +
                    '<div class="team-name">' + escHtml(name) + ' <span class="team-empid">' + escHtml(empId) + '</span></div>' +
                    '<div class="team-meta">' + formatRole(role) +
                    (curJob ? ' &bull; ' + escHtml(curJob) : '') +
                    (curMachine ? ' &bull; ' + escHtml(curMachine) : '') + '</div>' +
                '</div>' +
                '<span class="badge ' + status + '">' + status + '</span>' +
            '</div>';
        }
    }
    container.innerHTML = html;
}

// ---- RENDER: ASSIGN WORK (Manager Only) - Staff-First Picker ----
var selectedAssignStaff = null;

function renderAssignments() {
    var picker = document.getElementById('staffPicker');
    if (!picker) return;

    var unassignedCount = 0;
    for (var i = 0; i < allJobs.length; i++) {
        var st = ev(allJobs[i].job_status);
        if (st === 'not_started' && !ev(allJobs[i].assigned_to)) unassignedCount++;
    }
    document.getElementById('unassignedCount').innerHTML = unassignedCount + ' unassigned';

    var html = '';
    for (var j = 0; j < allStaff.length; j++) {
        var s = allStaff[j];
        var sid = eid(s.sys_id);
        var name = ev(s.name);
        var status = ev(s.status);
        var workCount = countStaffJobs(sid);
        html += '<div class="staff-chip' + (selectedAssignStaff === sid ? ' selected' : '') + '" id="chip_' + sid + '" onclick="selectStaffForAssign(\'' + sid + '\')">' +
            '<div class="chip-avatar">' + (name ? name.charAt(0).toUpperCase() : '?') + '</div>' +
            '<div><div class="chip-name">' + escHtml(name) + '</div>' +
            '<div class="chip-meta">' + workCount + ' jobs &bull; ' + status + '</div></div>' +
        '</div>';
    }
    picker.innerHTML = html;

    if (!selectedAssignStaff && allStaff.length > 0) {
        var first = allStaff[0];
        for (var k = 0; k < allStaff.length; k++) {
            if (ev(allStaff[k].status) === 'available') { first = allStaff[k]; break; }
        }
        selectStaffForAssign(eid(first.sys_id));
    } else if (selectedAssignStaff) {
        renderAssignDashboard(selectedAssignStaff);
    }
}

function countStaffJobs(staffSysId) {
    var count = 0;
    for (var i = 0; i < allJobs.length; i++) {
        var aId = eid(allJobs[i].assigned_to);
        var st = ev(allJobs[i].job_status);
        if (aId === staffSysId && st !== 'complete' && st !== 'shipped') count++;
    }
    return count;
}

function selectStaffForAssign(sysId) {
    selectedAssignStaff = sysId;
    var chips = document.querySelectorAll('.staff-chip');
    for (var i = 0; i < chips.length; i++) {
        chips[i].className = chips[i].id === 'chip_' + sysId ? 'staff-chip selected' : 'staff-chip';
    }
    renderAssignDashboard(sysId);
}

function renderAssignDashboard(staffSysId) {
    var dashboard = document.getElementById('assignDashboard');
    if (!dashboard) return;

    var staffName = '';
    for (var n = 0; n < allStaff.length; n++) {
        if (eid(allStaff[n].sys_id) === staffSysId) { staffName = ev(allStaff[n].name); break; }
    }

    // Left: their assigned jobs
    var theirJobs = [];
    for (var i = 0; i < allJobs.length; i++) {
        var aId = eid(allJobs[i].assigned_to);
        var st = ev(allJobs[i].job_status);
        if (aId === staffSysId && st !== 'complete' && st !== 'shipped') theirJobs.push(allJobs[i]);
    }

    // Right: unassigned jobs
    var available = [];
    for (var j = 0; j < allJobs.length; j++) {
        var jb = allJobs[j];
        var jSt = ev(jb.job_status);
        if ((jSt === 'not_started') && !ev(jb.assigned_to)) available.push(jb);
    }

    var leftHtml = '<div class="assign-col-header">' + escHtml(staffName) + '\'s Jobs (' + theirJobs.length + ')</div>';
    if (theirJobs.length === 0) {
        leftHtml += '<div class="empty-state"><p>No current assignments</p></div>';
    } else {
        for (var k = 0; k < theirJobs.length; k++) {
            var o = theirJobs[k];
            var oSt = ev(o.job_status);
            leftHtml += '<div class="op-item" style="cursor:default;">' +
                '<div class="op-seq">' + escHtml(ev(o.priority)).charAt(0).toUpperCase() + '</div>' +
                '<div class="op-info">' +
                    '<div class="op-name">' + escHtml(ev(o.job_number)) + '</div>' +
                    '<div class="op-meta"><span>' + escHtml(ev(o.po_number)) + '</span><span>Qty: ' + ev(o.quantity_due) + '</span></div>' +
                '</div>' +
                '<span class="badge ' + oSt + '">' + oSt.replace(/_/g, ' ') + '</span>' +
            '</div>';
        }
    }

    var rightHtml = '<div class="assign-col-header">Available Jobs (' + available.length + ')</div>';
    rightHtml += '<input type="text" class="assign-filter" id="jobFilterInput" placeholder="Filter by job or PO number..." oninput="filterAvailableJobs()" />';
    rightHtml += '<div id="availableJobsList">';
    rightHtml += renderAvailableJobs(available);
    rightHtml += '</div>';

    dashboard.innerHTML = '<div class="assign-split">' +
        '<div class="assign-col">' + leftHtml + '</div>' +
        '<div class="assign-col">' + rightHtml + '</div>' +
    '</div>';
}

function renderAvailableJobs(jobs) {
    if (jobs.length === 0) return '<div class="empty-state"><p>All jobs assigned!</p></div>';
    var html = '';
    for (var i = 0; i < jobs.length; i++) {
        var jb = jobs[i];
        var sid = eid(jb.sys_id);
        var pri = ev(jb.priority);
        html += '<div class="op-item assign-available-op">' +
            '<div class="op-seq" style="' +
                (pri === 'critical' ? 'background:rgba(239,68,68,0.2);color:#EF4444;' :
                 pri === 'high' ? 'background:rgba(245,158,11,0.2);color:#F59E0B;' : '') + '">' +
                escHtml(pri ? pri.charAt(0).toUpperCase() : '?') + '</div>' +
            '<div class="op-info">' +
                '<div class="op-name">' + escHtml(ev(jb.job_number)) + '</div>' +
                '<div class="op-meta"><span>' + escHtml(ev(jb.po_number)) + '</span><span>Qty: ' + ev(jb.quantity_due) + '</span>' +
                (ev(jb.customer_due_date) ? '<span>Due: ' + escHtml(ev(jb.customer_due_date)) + '</span>' : '') + '</div>' +
            '</div>' +
            '<button class="quick-assign-btn" onclick="quickAssignJob(\'' + sid + '\')">+ Assign</button>' +
        '</div>';
    }
    return html;
}

function filterAvailableJobs() {
    var input = document.getElementById('jobFilterInput');
    var filter = input ? input.value.toLowerCase() : '';
    var available = [];
    for (var i = 0; i < allJobs.length; i++) {
        var jb = allJobs[i];
        if (ev(jb.job_status) !== 'not_started' || ev(jb.assigned_to)) continue;
        if (filter) {
            var jn = ev(jb.job_number).toLowerCase();
            var po = ev(jb.po_number).toLowerCase();
            if (jn.indexOf(filter) === -1 && po.indexOf(filter) === -1) continue;
        }
        available.push(jb);
    }
    var list = document.getElementById('availableJobsList');
    if (list) list.innerHTML = renderAvailableJobs(available);
}

function quickAssignJob(jobSysId) {
    if (!selectedAssignStaff) { showToast('Select a staff member first', 'error'); return; }
    var staffName = '';
    for (var i = 0; i < allStaff.length; i++) {
        if (eid(allStaff[i].sys_id) === selectedAssignStaff) { staffName = ev(allStaff[i].name); break; }
    }
    apiPatch('x_1964226_svem_com_jobs', jobSysId, {
        assigned_to: selectedAssignStaff,
        job_status: 'assigned'
    }).then(function() {
        showToast('Job assigned to ' + staffName, 'success');
        return refreshAll();
    }).catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

// ---- RENDER: REVIEW (Manager Only) ----
function renderReview() {
    var container = document.getElementById('reviewList');
    if (!container) return;

    var pending = [];
    var recentlyCompleted = [];
    for (var i = 0; i < allJobs.length; i++) {
        var jb = allJobs[i];
        var st = ev(jb.job_status);
        if (st === 'pending_review') {
            pending.push(jb);
        } else if (st === 'complete') {
            recentlyCompleted.push(jb);
        }
    }

    document.getElementById('reviewCount').innerHTML = pending.length + ' pending';

    var html = '';
    if (pending.length > 0) {
        html += '<div class="stage-label review">&#9888; Needs Your Approval (' + pending.length + ')</div>';
        for (var j = 0; j < pending.length; j++) {
            var jb = pending[j];
            var assignee = ev(jb.assigned_to);
            var sid = eid(jb.sys_id);

            html += '<div class="review-card">' +
                '<div class="review-header">' +
                    '<div>' +
                        '<div class="review-job">' + escHtml(ev(jb.job_number)) + ' &bull; ' + escHtml(ev(jb.po_number)) + '</div>' +
                        '<div class="review-meta">By: ' + escHtml(assignee) + ' &bull; Qty: ' + ev(jb.quantity_due) + '</div>' +
                    '</div>' +
                    '<span class="badge pending_review">pending review</span>' +
                '</div>' +
                '<div class="review-actions">' +
                    '<button class="action-btn success" onclick="approveJob(\'' + sid + '\')">&#10003; Approve</button>' +
                    '<button class="action-btn danger" onclick="rejectJob(\'' + sid + '\')">&#10007; Reject</button>' +
                '</div>' +
            '</div>';
        }
    }

    if (recentlyCompleted.length > 0) {
        html += '<div class="stage-label complete">&#10003; Recently Completed (' + Math.min(recentlyCompleted.length, 10) + ')</div>';
        for (var k = 0; k < Math.min(recentlyCompleted.length, 10); k++) {
            var oc = recentlyCompleted[k];
            html += '<div class="op-item" style="opacity:0.7;cursor:default;">' +
                '<div class="op-seq" style="background:rgba(34,197,94,0.2);color:#22C55E;">&#10003;</div>' +
                '<div class="op-info">' +
                    '<div class="op-name">' + escHtml(ev(oc.job_number)) + '</div>' +
                    '<div class="op-meta"><span>' + escHtml(ev(oc.po_number)) + '</span><span>' + escHtml(ev(oc.assigned_to)) + '</span></div>' +
                '</div>' +
                '<span class="badge complete">complete</span>' +
            '</div>';
        }
    }

    if (html === '') {
        html = '<div class="empty-state"><p>No jobs to review.</p></div>';
    }
    container.innerHTML = html;
}

// ---- RENDER: MACHINES ----
function renderMachines() {
    var container = document.getElementById('machineList');
    var runCount = 0;
    for (var i = 0; i < allMachines.length; i++) {
        if (ev(allMachines[i].status) === 'running') runCount++;
    }
    document.getElementById('machineCount').innerHTML = runCount + '/' + allMachines.length + ' running';

    if (allMachines.length === 0) {
        container.innerHTML = '<div class="empty-state"><p>No machines found</p></div>';
        return;
    }

    var html = '<div class="machine-grid">';
    for (var j = 0; j < allMachines.length; j++) {
        var m = allMachines[j];
        var status = ev(m.status) || 'idle';
        var name = ev(m.machine_name);
        var number = ev(m.machine_number);
        var job = ev(m.current_job);
        var sysId = eid(m.sys_id);

        html += '<div class="machine-card ' + status + '" onclick="openMachineModal(\'' + sysId + '\')">' +
            '<div class="machine-card-name">' + escHtml(name) + '</div>' +
            '<div class="machine-card-number">' + escHtml(number) + '</div>' +
            '<span class="badge ' + status + '">' + status + '</span>' +
            (job ? '<div class="machine-card-job">' + escHtml(job) + '</div>' : '') +
        '</div>';
    }
    html += '</div>';
    container.innerHTML = html;
}

// ---- RENDER: PROFILE ----
function renderProfile() {
    if (!staffRecord) return;
    document.getElementById('profileEmpId').innerHTML = ev(staffRecord.employee_id) || '--';
    document.getElementById('profileRole').innerHTML = formatRole(ev(staffRecord.role));
    document.getElementById('profileShift').innerHTML = (ev(staffRecord.shift) || '--').toUpperCase();
    document.getElementById('profileStatus').innerHTML = '<span class="badge ' + ev(staffRecord.status) + '">' + ev(staffRecord.status) + '</span>';
    document.getElementById('profileMachine').innerHTML = ev(staffRecord.current_machine) || 'None';

    var completedCount = 0;
    for (var i = 0; i < myJobs.length; i++) {
        if (ev(myJobs[i].job_status) === 'complete') completedCount++;
    }
    document.getElementById('statJobsCompleted').innerHTML = completedCount;
    document.getElementById('statHoursLogged').innerHTML = myJobs.length;
}

// ======= ACTIONS =======

// -- Employee: start job --
function startJobConfirm(sysId) {
    var job = findJob(sysId);
    if (!job) return;
    var status = ev(job.job_status);
    if (status === 'assigned') {
        if (confirm('Start working on ' + ev(job.job_number) + '?')) startJob(sysId);
    } else if (status === 'not_started') {
        showToast('This job needs to be assigned first', 'error');
    }
}

function startJob(sysId) {
    apiPatch('x_1964226_svem_com_jobs', sysId, {
        job_status: 'in_progress'
    }).then(function() {
        showToast('Job started!', 'success');
        return refreshAll();
    }).catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

function pauseJob(sysId) {
    apiPatch('x_1964226_svem_com_jobs', sysId, { job_status: 'assigned' })
    .then(function() {
        showToast('Job paused', 'success');
        stopTimer();
        return refreshAll();
    }).catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

function submitJobForReview(sysId) {
    if (!confirm('Submit this job for manager review?')) return;
    apiPatch('x_1964226_svem_com_jobs', sysId, { job_status: 'pending_review' })
    .then(function() {
        showToast('Submitted for review!', 'success');
        stopTimer();
        return refreshAll();
    }).catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

// -- Manager: approve/reject --
function approveJob(sysId) {
    if (!confirm('Approve this job as complete?')) return;
    apiPatch('x_1964226_svem_com_jobs', sysId, {
        job_status: 'complete'
    }).then(function() {
        showToast('Job approved!', 'success');
        return refreshAll();
    }).catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

function rejectJob(sysId) {
    var reason = prompt('Reason for rejection (optional):');
    apiPatch('x_1964226_svem_com_jobs', sysId, {
        job_status: 'assigned',
        notes: reason ? 'REJECTED: ' + reason : 'REJECTED - Needs rework'
    }).then(function() {
        showToast('Job rejected and sent back', 'success');
        return refreshAll();
    }).catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

// -- Manager: add staff --
function showAddStaff() {
    document.getElementById('addStaffModal').className = 'modal-overlay active';
}

function createStaffMember() {
    var name = document.getElementById('newStaffName').value.trim();
    var role = document.getElementById('newStaffRole').value;
    var shift = document.getElementById('newStaffShift').value;

    if (!name) { showToast('Name is required', 'error'); return; }
    if (!role) { showToast('Role is required', 'error'); return; }

    apiPost('x_1964226_svem_com_staff', {
        name: name,
        role: role,
        shift: shift || 'day',
        status: 'available'
    }).then(function() {
        showToast('Staff member added!', 'success');
        closeModal('addStaffModal');
        document.getElementById('newStaffName').value = '';
        return loadAllStaff();
    }).then(function() {
        renderTeam();
        renderAssignments();
    }).catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

// -- Clock in/out --
function toggleClock() {
    if (!staffRecord) { showToast('Staff record not found', 'error'); return; }
    var newStatus = clockedIn ? 'off' : 'available';
    apiPatch('x_1964226_svem_com_staff', eid(staffRecord.sys_id), { status: newStatus })
    .then(function() {
        clockedIn = !clockedIn;
        staffRecord.status = { display_value: newStatus, value: newStatus };
        updateClockBtn();
        renderProfile();
        if (isManager) renderTeam();
        showToast(clockedIn ? 'Clocked in!' : 'Clocked out!', 'success');
    }).catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

function updateClockBtn() {
    var btn = document.getElementById('clockBtn');
    btn.innerHTML = clockedIn ? 'Clock Out' : 'Clock In';
    btn.className = 'clock-btn ' + (clockedIn ? 'clock-out' : 'clock-in');
}

// -- Machine modal --
function openMachineModal(sysId) {
    var machine = null;
    for (var i = 0; i < allMachines.length; i++) {
        if (eid(allMachines[i].sys_id) === sysId) { machine = allMachines[i]; break; }
    }
    if (!machine) return;
    selectedMachineSysId = sysId;
    selectedMachineStatus = ev(machine.status);
    document.getElementById('machineModalName').innerHTML = escHtml(ev(machine.machine_name));
    document.getElementById('machineModalInfo').innerHTML = escHtml(ev(machine.machine_number)) + ' &bull; ' + escHtml(ev(machine.machine_type));
    var opts = document.querySelectorAll('.status-option');
    for (var j = 0; j < opts.length; j++) opts[j].className = 'status-option';
    document.getElementById('machineModal').className = 'modal-overlay active';
}

function selectMachineStatus(status, el) {
    selectedMachineStatus = status;
    var opts = document.querySelectorAll('.status-option');
    for (var i = 0; i < opts.length; i++) opts[i].className = 'status-option';
    el.className = 'status-option selected';
}

function saveMachineStatus() {
    if (!selectedMachineSysId || !selectedMachineStatus) return;
    apiPatch('x_1964226_svem_com_machines', selectedMachineSysId, { status: selectedMachineStatus })
    .then(function() {
        showToast('Machine status updated!', 'success');
        closeModal('machineModal');
        return loadMachines();
    }).then(function() { renderMachines(); })
    .catch(function(e) { showToast('Error: ' + e.message, 'error'); });
}

function openStaffDetail(sysId) {
    var s = null;
    for (var i = 0; i < allStaff.length; i++) {
        if (eid(allStaff[i].sys_id) === sysId) { s = allStaff[i]; break; }
    }
    if (!s) return;
    window.open('/x_1964226_svem_com_staff.do?sys_id=' + sysId, '_blank');
}

// ======= HELPERS =======
function refreshAll() {
    return Promise.all([loadAllStaff(), loadMachines(), loadJobs()])
    .then(function() {
        filterMyJobs();
        renderTasks();
        renderMachines();
        renderProfile();
        if (isManager) { renderTeam(); renderAssignments(); renderReview(); }
    });
}

// ---- VIEW AS (Manager) ----
function switchViewAs() {
    var sel = document.getElementById('viewAsSelect');
    viewAsStaffId = sel ? sel.value : '';
    if (viewAsStaffId) {
        // Switch context to selected staff member
        for (var i = 0; i < allStaff.length; i++) {
            if (eid(allStaff[i].sys_id) === viewAsStaffId) { staffRecord = allStaff[i]; break; }
        }
        var name = ev(staffRecord.name);
        document.getElementById('userName').innerHTML = escHtml(name) + ' <span style="font-size:10px;color:#F59E0B;">(viewing as)</span>';
        document.getElementById('userAvatar').innerHTML = name ? name.charAt(0).toUpperCase() : '?';
    } else {
        // Reset to self
        staffRecord = null;
        for (var j = 0; j < allStaff.length; j++) {
            if (ev(allStaff[j].name) === currentUserFullName) { staffRecord = allStaff[j]; break; }
        }
        if (!staffRecord && allStaff.length > 0) staffRecord = allStaff[0];
        var n = staffRecord ? ev(staffRecord.name) : currentUserFullName;
        document.getElementById('userName').innerHTML = escHtml(n);
        document.getElementById('userAvatar').innerHTML = n ? n.charAt(0).toUpperCase() : '?';
    }
    filterMyJobs();
    renderTasks();
    renderProfile();
}

// ---- ORG CHART ----
function renderOrgChart() {
    var container = document.getElementById('orgChart');
    if (!container) return;

    // Group staff by role
    var roleGroups = {};
    var roleOrder = ['manager','supervisor','programmer','setup_operator','operator','qc_technician','deburr_operator','material_handler','shipping_technician','driver'];
    var roleColors = { manager:'#F59E0B', supervisor:'#F59E0B', programmer:'#8B5CF6', setup_operator:'#3B82F6', operator:'#3B82F6', qc_technician:'#22C55E', deburr_operator:'#06B6D4', material_handler:'#EC4899', shipping_technician:'#F97316', driver:'#F97316' };

    for (var i = 0; i < allStaff.length; i++) {
        var role = ev(allStaff[i].role) || 'other';
        if (!roleGroups[role]) roleGroups[role] = [];
        roleGroups[role].push(allStaff[i]);
    }

    // Manager/supervisor at top
    var html = '<div class="org-tree">';

    // Top: Management
    var mgrs = (roleGroups['manager'] || []).concat(roleGroups['supervisor'] || []);
    if (mgrs.length > 0) {
        html += '<div class="org-level org-top">';
        for (var m = 0; m < mgrs.length; m++) {
            html += orgNode(mgrs[m], roleColors[ev(mgrs[m].role)] || '#F59E0B');
        }
        html += '</div>';
        html += '<div class="org-connector"></div>';
    } else {
        // Show admin as implicit manager
        html += '<div class="org-level org-top">';
        html += '<div class="org-node" style="border-color:#F59E0B;"><div class="org-node-avatar" style="background:#F59E0B;">' + (currentUserFullName ? currentUserFullName.charAt(0) : 'A') + '</div>';
        html += '<div class="org-node-name">' + escHtml(currentUserFullName || 'Admin') + '</div>';
        html += '<div class="org-node-role">Manager</div></div>';
        html += '</div>';
        html += '<div class="org-connector"></div>';
    }

    // Middle: Technical roles
    var techRoles = ['programmer','setup_operator','qc_technician'];
    var techStaff = [];
    for (var t = 0; t < techRoles.length; t++) {
        if (roleGroups[techRoles[t]]) techStaff = techStaff.concat(roleGroups[techRoles[t]]);
    }
    if (techStaff.length > 0) {
        html += '<div class="org-section-label">Technical &amp; Quality</div>';
        html += '<div class="org-level">';
        for (var ts = 0; ts < techStaff.length; ts++) {
            html += orgNode(techStaff[ts], roleColors[ev(techStaff[ts].role)] || '#3B82F6');
        }
        html += '</div>';
    }

    // Bottom: Operations roles
    var opsRoles = ['operator','deburr_operator','material_handler','shipping_technician','driver'];
    var opsStaff = [];
    for (var o = 0; o < opsRoles.length; o++) {
        if (roleGroups[opsRoles[o]]) opsStaff = opsStaff.concat(roleGroups[opsRoles[o]]);
    }
    if (opsStaff.length > 0) {
        html += '<div class="org-section-label">Operations &amp; Logistics</div>';
        html += '<div class="org-level">';
        for (var os = 0; os < opsStaff.length; os++) {
            html += orgNode(opsStaff[os], roleColors[ev(opsStaff[os].role)] || '#3B82F6');
        }
        html += '</div>';
    }

    // Any ungrouped
    var shown = ['manager','supervisor'].concat(techRoles).concat(opsRoles);
    var other = [];
    for (var role in roleGroups) {
        if (shown.indexOf(role) === -1) other = other.concat(roleGroups[role]);
    }
    if (other.length > 0) {
        html += '<div class="org-section-label">Other</div>';
        html += '<div class="org-level">';
        for (var ot = 0; ot < other.length; ot++) {
            html += orgNode(other[ot], '#6B7280');
        }
        html += '</div>';
    }

    html += '</div>';

    // Stats summary
    html += '<div class="org-stats">';
    html += '<div class="org-stat"><span class="org-stat-num">' + allStaff.length + '</span><span class="org-stat-label">Total Staff</span></div>';
    var activeCount = 0;
    for (var ac = 0; ac < allStaff.length; ac++) { var ss = ev(allStaff[ac].status); if (ss === 'available' || ss === 'assigned') activeCount++; }
    html += '<div class="org-stat"><span class="org-stat-num" style="color:#22C55E;">' + activeCount + '</span><span class="org-stat-label">On Shift</span></div>';
    var roleCount = Object.keys(roleGroups).length;
    html += '<div class="org-stat"><span class="org-stat-num" style="color:#8B5CF6;">' + roleCount + '</span><span class="org-stat-label">Roles</span></div>';
    html += '</div>';

    container.innerHTML = html;
}

function orgNode(staff, color) {
    var name = ev(staff.name);
    var role = ev(staff.role);
    var status = ev(staff.status);
    var empId = ev(staff.employee_id);
    var statusDot = status === 'available' || status === 'assigned' ? '#22C55E' : '#8B8D97';
    return '<div class="org-node" style="border-color:' + color + ';">' +
        '<div class="org-node-avatar" style="background:' + color + ';">' + (name ? name.charAt(0).toUpperCase() : '?') +
        '<span class="org-status-dot" style="background:' + statusDot + ';"></span></div>' +
        '<div class="org-node-name">' + escHtml(name) + '</div>' +
        '<div class="org-node-role">' + formatRole(role) + '</div>' +
        (empId ? '<div class="org-node-id">' + escHtml(empId) + '</div>' : '') +
    '</div>';
}

function findJob(sysId) {
    for (var i = 0; i < allJobs.length; i++) {
        if (eid(allJobs[i].sys_id) === sysId) return allJobs[i];
    }
    return null;
}

function nowStr() { return new Date().toISOString().replace('T', ' ').split('.')[0]; }

function startTimer() {
    if (activeTimer) return;
    timerStart = Date.now(); timerElapsed = 0;
    activeTimer = setInterval(function() {
        timerElapsed = (Date.now() - timerStart) / 1000;
        var h = Math.floor(timerElapsed / 3600);
        var m = Math.floor((timerElapsed % 3600) / 60);
        var s = Math.floor(timerElapsed % 60);
        var el = document.getElementById('taskTimer');
        if (el) el.innerHTML = pad(h) + ':' + pad(m) + ':' + pad(s);
    }, 1000);
}
function stopTimer() { if (activeTimer) { clearInterval(activeTimer); activeTimer = null; } timerElapsed = 0; }
function pad(n) { return (n < 10 ? '0' : '') + n; }

function switchTab(tabName, btn) {
    var tabs = document.querySelectorAll('.tab-content');
    for (var i = 0; i < tabs.length; i++) tabs[i].className = 'tab-content';
    var btns = document.querySelectorAll('.tab-btn');
    for (var j = 0; j < btns.length; j++) { btns[j].className = btns[j].className.replace(' active', ''); }
    document.getElementById('tab-' + tabName).className = 'tab-content active';
    btn.className += ' active';
}

function closeModal(id) { document.getElementById(id).className = 'modal-overlay'; }
function showToast(msg, type) {
    var t = document.getElementById('toast');
    t.innerHTML = escHtml(msg); t.className = 'toast ' + (type || '') + ' show';
    setTimeout(function() { t.className = 'toast'; }, 2500);
}
function formatRole(role) {
    var map = { operator:'Operator', setup_operator:'Setup Operator', qc_technician:'QC Tech', programmer:'Programmer', deburr_operator:'Deburr Op', material_handler:'Material Handler', driver:'Driver', shipping_technician:'Shipping Tech', manager:'Manager', supervisor:'Supervisor' };
    return map[role] || (role || '').replace(/_/g, ' ');
}
function escHtml(s) { if (!s) return ''; var d = document.createElement('div'); d.appendChild(document.createTextNode(s)); return d.innerHTML; }
